/**
 * Generate Etherscan firewall config.
 *
 * Data source: https://docs.etherscan.io/getting-started
 *
 * Etherscan API V2 authenticates requests with an `apikey` query parameter.
 * One API key works across supported chains by changing the `chainid`
 * parameter.
 */

import { writeOutput } from "./codegen";

const DOCS_URL = "https://docs.etherscan.io/getting-started";
const PLACEHOLDER_VALUE = "CoffeeSafeLocalCoffeeSafeLocalCoffeeSafe";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Etherscan API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:etherscan",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const etherscanFirewall = {",
    '  name: "etherscan",',
    '  description: "Etherscan API V2",',
    "  placeholders: {",
    `    ETHERSCAN_API_KEY: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.etherscan.io/v2/api",',
    "      auth: {",
    "        query: {",
    '          apikey: "${{ secrets.ETHERSCAN_API_KEY }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Etherscan firewall config...");
  const ts = generateTypeScript();
  writeOutput("etherscan", ts, import.meta.dirname);
}
